// worker-orders.js - Order service worker
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    try {
      if (path === '/api/orders' && method === 'GET') {
        const orders = await this.getOrders(env);
        
        return new Response(JSON.stringify(orders), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path.startsWith('/api/orders/') && method === 'GET') {
        const orderId = path.split('/')[3];
        const order = await this.getOrder(orderId, env);
        
        return new Response(JSON.stringify(order), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path === '/api/orders' && method === 'POST') {
        const orderData = await request.json();
        
        // Verify user exists
        if (env.USER_SERVICE) {
          const userResponse = await env.USER_SERVICE.fetch(
            new Request(`http://internal/api/users/${orderData.userId}`)
          );
          if (!userResponse.ok) {
            return new Response(JSON.stringify({ error: 'User not found' }), {
              status: 400,
              headers: { 'Content-Type': 'application/json' }
            });
          }
        }

        // Verify products exist
        if (env.PRODUCT_SERVICE && orderData.products) {
          for (const item of orderData.products) {
            const productResponse = await env.PRODUCT_SERVICE.fetch(
              new Request(`http://internal/api/products/${item.productId}`)
            );
            if (!productResponse.ok) {
              return new Response(JSON.stringify({ 
                error: `Product ${item.productId} not found` 
              }), {
                status: 400,
                headers: { 'Content-Type': 'application/json' }
              });
            }
          }
        }

        const order = await this.createOrder(orderData, env);

        // Send notification
        if (env.NOTIFICATION_SERVICE) {
          ctx.waitUntil(
            env.NOTIFICATION_SERVICE.fetch(
              new Request('http://internal/send', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  type: 'order_created',
                  orderId: order.id,
                  userId: order.userId
                })
              })
            )
          );
        }

        // Track analytics
        if (env.ANALYTICS_SERVICE) {
          ctx.waitUntil(
            env.ANALYTICS_SERVICE.fetch(
              new Request('http://internal/track', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  service: 'orders',
                  action: 'create',
                  orderId: order.id,
                  total: order.total,
                  timestamp: Date.now()
                })
              })
            )
          );
        }

        return new Response(JSON.stringify(order), {
          status: 201,
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({ error: 'Method not allowed' }), {
          status: 405,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Order service error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  },

  async getOrders(env) {
    const ordersData = await env.ORDERS_KV.get('orders_list', { type: 'json' });
    return ordersData || [];
  },

  async getOrder(orderId, env) {
    const order = await env.ORDERS_KV.get(`order:${orderId}`, { type: 'json' });
    return order || { error: 'Order not found' };
  },

  async createOrder(orderData, env) {
    const orderId = crypto.randomUUID();
    const order = {
      id: orderId,
      ...orderData,
      status: 'pending',
      createdAt: new Date().toISOString()
    };
    
    await env.ORDERS_KV.put(`order:${orderId}`, JSON.stringify(order));
    
    const orders = await this.getOrders(env);
    orders.push({ 
      id: orderId, 
      userId: orderData.userId, 
      total: orderData.total,
      status: 'pending'
    });
    await env.ORDERS_KV.put('orders_list', JSON.stringify(orders));
    
    return order;
  }
};


// worker-analytics.js - Analytics service worker
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    try {
      if (path === '/track' && method === 'POST') {
        const eventData = await request.json();
        await this.trackEvent(eventData, env);
        
        return new Response(JSON.stringify({ success: true }), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path === '/api/analytics' && method === 'GET') {
        const analytics = await this.getAnalytics(env);
        
        return new Response(JSON.stringify(analytics), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path === '/api/analytics/service' && method === 'GET') {
        const service = url.searchParams.get('name');
        const serviceAnalytics = await this.getServiceAnalytics(service, env);
        
        return new Response(JSON.stringify(serviceAnalytics), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({ error: 'Method not allowed' }), {
          status: 405,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Analytics service error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  },

  async trackEvent(eventData, env) {
    const eventId = crypto.randomUUID();
    const event = {
      id: eventId,
      ...eventData,
      recordedAt: new Date().toISOString()
    };
    
    await env.ANALYTICS_KV.put(`event:${eventId}`, JSON.stringify(event));
    
    const events = await env.ANALYTICS_KV.get('events_list', { type: 'json' }) || [];
    events.push(event);
    await env.ANALYTICS_KV.put('events_list', JSON.stringify(events));
    
    const serviceKey = `service:${eventData.service}`;
    const serviceEvents = await env.ANALYTICS_KV.get(serviceKey, { type: 'json' }) || [];
    serviceEvents.push(event);
    await env.ANALYTICS_KV.put(serviceKey, JSON.stringify(serviceEvents));
  },

  async getAnalytics(env) {
    const events = await env.ANALYTICS_KV.get('events_list', { type: 'json' }) || [];
    
    const summary = {
      totalEvents: events.length,
      byService: {},
      byAction: {},
      recentEvents: events.slice(-10)
    };
    
    events.forEach(event => {
      summary.byService[event.service] = (summary.byService[event.service] || 0) + 1;
      summary.byAction[event.action] = (summary.byAction[event.action] || 0) + 1;
    });
    
    return summary;
  },

  async getServiceAnalytics(serviceName, env) {
    const serviceEvents = await env.ANALYTICS_KV.get(`service:${serviceName}`, { type: 'json' }) || [];
    
    return {
      service: serviceName,
      totalEvents: serviceEvents.length,
      events: serviceEvents
    };
  }
};


// worker-notifications.js - Notification service worker
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    try {
      if (path === '/send' && method === 'POST') {
        const notificationData = await request.json();
        const notification = await this.sendNotification(notificationData, env);
        
        if (env.ANALYTICS_SERVICE) {
          ctx.waitUntil(
            env.ANALYTICS_SERVICE.fetch(
              new Request('http://internal/track', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                  service: 'notifications',
                  action: 'send',
                  type: notificationData.type,
                  timestamp: Date.now()
                })
              })
            )
          );
        }
        
        return new Response(JSON.stringify(notification), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path === '/api/notifications' && method === 'GET') {
        const notifications = await this.getNotifications(env);
        
        return new Response(JSON.stringify(notifications), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({ error: 'Method not allowed' }), {
          status: 405,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Notification service error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  },

  async sendNotification(notificationData, env) {
    const notificationId = crypto.randomUUID();
    const notification = {
      id: notificationId,
      ...notificationData,
      status: 'sent',
      sentAt: new Date().toISOString()
    };
    
    await env.NOTIFICATIONS_KV.put(`notification:${notificationId}`, JSON.stringify(notification));
    
    const notifications = await env.NOTIFICATIONS_KV.get('notifications_list', { type: 'json' }) || [];
    notifications.push(notification);
    await env.NOTIFICATIONS_KV.put('notifications_list', JSON.stringify(notifications));
    
    return notification;
  },

  async getNotifications(env) {
    const notifications = await env.NOTIFICATIONS_KV.get('notifications_list', { type: 'json' }) || [];
    return notifications;
  }
};


